insert into public.systems (id,name,slug,description,seo_title,seo_description,status,sort_order) values
('10000000-0000-4000-8000-000000000001','Skin Rejuvenation & Resurfacing','skin-rejuvenation-resurfacing','A structured system for professional skin-remodeling and resurfacing applications using depth- and mechanism-specific technologies.','Skin Rejuvenation & Resurfacing System','Explore professional skin rejuvenation technologies, applications, and platforms organized within a structured treatment system.','published',10),
('10000000-0000-4000-8000-000000000002','Hair Removal & Pigment Correction','hair-removal-pigment-correction','A structured laser system for professional hair-reduction and pigment-focused treatment applications.','Hair Removal & Pigment Correction System','Explore laser technologies and professional platforms for hair-removal and pigment-correction treatment planning.','published',20)
insert into public.technologies (id,name,slug,type,definition,mechanism,seo_title,seo_description,status,sort_order) values
('20000000-0000-4000-8000-000000000001','Fractional Radiofrequency','fractional-radiofrequency','energy','Controlled radiofrequency energy delivered through a fractional microneedle array.','Microneedles create controlled treatment zones while radiofrequency energy is delivered at selected depths for professional skin-remodeling workflows.','Fractional Radiofrequency Technology','Understand fractional radiofrequency mechanisms, clinical applications, related systems, and professional aesthetic platforms.','published',10),
('20000000-0000-4000-8000-000000000002','Diode Laser Technology','diode-laser','light','Semiconductor laser technology used in professional hair-reduction treatment pathways.','Selected wavelengths target melanin in the hair follicle while contact cooling supports professional treatment workflows.','Diode Laser Hair-Removal Technology','Understand diode laser mechanisms, hair-removal applications, system relationships, and available professional platforms.','published',20),
('20000000-0000-4000-8000-000000000003','Q-Switched Nd:YAG Laser','q-switched-nd-yag','light','Short-pulse laser technology used in professional pigment and tattoo-removal pathways.','Nanosecond pulses deliver wavelength-specific energy to selected pigment targets according to color, depth, and skin-type assessment.','Q-Switched Nd:YAG Laser Technology','Explore Q-switched Nd:YAG mechanisms, pigment applications, system relationships, and professional platforms.','published',30)
insert into public.applications (id,name,slug,description,clinical_outcomes,clinical_disclaimer,seo_title,seo_description,status,sort_order) values
('30000000-0000-4000-8000-000000000001','Skin Texture Remodeling','skin-texture-remodeling','Professional treatment planning focused on uneven texture and controlled skin-remodeling pathways.',array['Improved appearance of skin texture','Protocol-dependent skin remodeling'],'Outcomes vary by client, indication, protocol, operator, product configuration, and intended use.','Skin Texture Remodeling Technologies','Explore systems, technologies, and professional platforms supporting skin-texture remodeling treatment planning.','published',10),
('30000000-0000-4000-8000-000000000002','Laser Hair Removal','laser-hair-removal','Professional reduction of unwanted hair using wavelength- and skin-type-aware treatment planning.',array['Progressive hair reduction','Treatment planning across face and body areas'],'Outcomes vary by client, hair characteristics, skin type, protocol, operator, and intended use.','Laser Hair Removal Technologies','Explore diode laser systems, technologies, and professional platforms for laser hair-removal treatment planning.','published',20),
('30000000-0000-4000-8000-000000000003','Pigmentation Correction','pigmentation-correction','Professional wavelength selection and treatment planning for suitable benign pigmented lesions.',array['Improved appearance of selected pigmentation'],'Suitability and outcomes require professional assessment and vary by client, lesion, protocol, operator, and intended use.','Pigmentation Correction Laser Technologies','Explore systems, Q-switched laser technology, and professional platforms supporting pigmentation-correction planning.','published',30)
