insert into public.products (id,name,short_name,slug,system_id,primary_technology_id,description,workflow_role,key_features,specs,regulatory_note,content_generated_by,ai_core_version,seo_title,seo_description,status,sort_order) values
('40000000-0000-4000-8000-000000000001','AURA RF','RF Microneedling Platform','aura-rf','10000000-0000-4000-8000-000000000001','20000000-0000-4000-8000-000000000001','A professional fractional radiofrequency platform for controlled skin-remodeling applications.','Supports application-led selection of treatment depth, consumables, and workflow configuration.',array['Fractional RF delivery','Configurable treatment workflow','Professional application support'],'{}','Regulatory status, intended use, and available configurations vary by product and market.','AI_INTELLIGENCE_CORE','1.0.0','AURA RF Microneedling Platform','Review AURA RF clinical applications, fractional radiofrequency technology, parent system, features, and inquiry options.','published',10),
('40000000-0000-4000-8000-000000000002','AURA RF Compact','RF Microneedling Compact','aura-rf-compact','10000000-0000-4000-8000-000000000001','20000000-0000-4000-8000-000000000001','A compact professional fractional radiofrequency platform for structured skin-remodeling workflows.','Provides an alternative platform configuration within the Skin Rejuvenation & Resurfacing system.',array['Compact platform format','Fractional RF mechanism','Application-led configuration'],'{}','Regulatory status, intended use, and available configurations vary by product and market.','AI_INTELLIGENCE_CORE','1.0.0','AURA RF Compact Platform','Review AURA RF Compact applications, technology, system relationship, features, and configuration inquiry.','published',20),
('40000000-0000-4000-8000-000000000003','VELA DIODE','Diode Laser Platform','vela-diode','10000000-0000-4000-8000-000000000002','20000000-0000-4000-8000-000000000002','A professional diode laser platform for structured hair-reduction treatment workflows.','Supports application and market-led diode laser platform selection. ',array['Diode laser technology','Professional hair-reduction workflow','Configurable platform support'],'{}','Regulatory status, intended use, and available configurations vary by product and market.','AI_INTELLIGENCE_CORE','1.0.0','VELA Diode Laser Platform','Review VELA DIODE applications, diode laser technology, parent system, features, and inquiry options.','published',30),
('40000000-0000-4000-8000-000000000004','VELA DIODE Compact','Compact Diode Laser Platform','vela-diode-compact','10000000-0000-4000-8000-000000000002','20000000-0000-4000-8000-000000000002','A compact professional diode laser configuration for hair-reduction treatment workflows.','Provides an alternative diode laser configuration for selected professional operating models.',array['Compact platform format','Diode laser mechanism','Professional workflow support'],'{}','Regulatory status, intended use, and available configurations vary by product and market.','AI_INTELLIGENCE_CORE','1.0.0','VELA DIODE Compact Platform','Review VELA DIODE Compact applications, technology, system relationship, and configuration inquiry.','published',40),
('40000000-0000-4000-8000-000000000005','LUMA YAG','Q-Switched Nd:YAG Platform','luma-yag','10000000-0000-4000-8000-000000000002','20000000-0000-4000-8000-000000000003','A professional Q-switched Nd:YAG laser platform for pigment-focused treatment pathways.','Supports wavelength-aware pigment application planning within the Hair Removal & Pigment Correction system.',array['Q-switched laser technology','Pigment-focused workflow','Professional configuration support'],'{}','Regulatory status, intended use, and available configurations vary by product and market.','AI_INTELLIGENCE_CORE','1.0.0','LUMA YAG Laser Platform','Review LUMA YAG applications, Q-switched Nd:YAG technology, parent system, features, and inquiry options.','published',50)
