insert into public.faqs (id,question,answer,product_id,content_generated_by,ai_core_version,status,sort_order) values
('50000000-0000-4000-8000-000000000001','Which applications does AURA RF support?','The published application relationship currently connects this platform to professional skin-texture remodeling workflows. Final intended use varies by configuration and market.','40000000-0000-4000-8000-000000000001','AI_INTELLIGENCE_CORE','1.0.0','published',10),
('50000000-0000-4000-8000-000000000002','How does AURA RF Compact fit the system?','It is a compact fractional radiofrequency implementation within the Skin Rejuvenation & Resurfacing system.','40000000-0000-4000-8000-000000000002','AI_INTELLIGENCE_CORE','1.0.0','published',10),
('50000000-0000-4000-8000-000000000003','Which technology does VELA DIODE use?','The platform implements professional diode laser technology within the Hair Removal & Pigment Correction system.','40000000-0000-4000-8000-000000000003','AI_INTELLIGENCE_CORE','1.0.0','published',10),
('50000000-0000-4000-8000-000000000004','Who is VELA DIODE Compact intended for?','Configuration and intended use depend on market documentation and professional operating requirements. Contact NEWME MEDTECH for confirmation.','40000000-0000-4000-8000-000000000004','AI_INTELLIGENCE_CORE','1.0.0','published',10),
('50000000-0000-4000-8000-000000000005','Which applications are connected to LUMA YAG?','The current CMS relationship connects LUMA YAG to professional pigmentation-correction planning. Suitability requires professional assessment.','40000000-0000-4000-8000-000000000005','AI_INTELLIGENCE_CORE','1.0.0','published',10)
insert into public.pages (id,key,title,eyebrow,content,seo_title,seo_description,status) values
('60000000-0000-4000-8000-000000000001','home','Creating Beauty Through Technology.','Aesthetic technology, thoughtfully structured','{"intro":"Application-driven aesthetic technology systems that help professionals evaluate platforms, workflows, and market requirements.","hero_image":"/images/newme-hero-beauty-v2.png"}','NEWME MEDTECH Aesthetic Technology Systems','Explore structured aesthetic technology systems organized by clinical application, physical mechanism, and professional platform.','published'),
('60000000-0000-4000-8000-000000000002','about','Creating Beauty Through Technology.','About Us','{"lead":"NEWME MEDTECH was founded on a simple belief: beauty is created through expertise, innovation, and trusted technology.","paragraphs":["We work with clinics, practitioners, distributors, and beauty professionals to provide structured aesthetic technology solutions.","Our portfolio connects laser, radiofrequency, phototherapy, contouring, and skin-care technologies to professional applications.","We focus on helping partners evaluate systems, technologies, and platforms in clinical and operational context."]}','About NEWME MEDTECH','Learn how NEWME MEDTECH structures aesthetic technologies around professional applications, workflows, and partner support.','published'),
('60000000-0000-4000-8000-000000000003','contact','The right recommendation starts with context.','Request a consultation','{"intro":"Tell us about your market, business type, and treatment applications. A specialist will respond with relevant systems and configurations."}','Contact NEWME MEDTECH','Contact NEWME MEDTECH to discuss aesthetic technology systems, applications, configurations, and market documentation.','published'),
('60000000-0000-4000-8000-000000000004','blog','Decision frameworks for aesthetic professionals.','Clinical & Business Insights','{}','Aesthetic Technology Insights','Read structured guidance on aesthetic systems, technologies, applications, professional platforms, and market planning.','published')
