-- Minimal production seed for NEWME MEDTECH.
-- Content is intentionally conservative and must receive final product/regulatory review.
begin;

on conflict (id) do update set name=excluded.name,slug=excluded.slug,description=excluded.description,seo_title=excluded.seo_title,seo_description=excluded.seo_description,status=excluded.status,sort_order=excluded.sort_order;

on conflict (id) do update set name=excluded.name,slug=excluded.slug,type=excluded.type,definition=excluded.definition,mechanism=excluded.mechanism,seo_title=excluded.seo_title,seo_description=excluded.seo_description,status=excluded.status,sort_order=excluded.sort_order;

on conflict (id) do update set name=excluded.name,slug=excluded.slug,description=excluded.description,clinical_outcomes=excluded.clinical_outcomes,clinical_disclaimer=excluded.clinical_disclaimer,seo_title=excluded.seo_title,seo_description=excluded.seo_description,status=excluded.status,sort_order=excluded.sort_order;

on conflict (system_id,technology_id) do update set sort_order=excluded.sort_order;

on conflict (system_id,application_id) do update set sort_order=excluded.sort_order;

on conflict (technology_id,application_id) do update set sort_order=excluded.sort_order;

on conflict (id) do update set name=excluded.name,short_name=excluded.short_name,slug=excluded.slug,system_id=excluded.system_id,primary_technology_id=excluded.primary_technology_id,description=excluded.description,workflow_role=excluded.workflow_role,key_features=excluded.key_features,specs=excluded.specs,regulatory_note=excluded.regulatory_note,content_generated_by=excluded.content_generated_by,ai_core_version=excluded.ai_core_version,seo_title=excluded.seo_title,seo_description=excluded.seo_description,status=excluded.status,sort_order=excluded.sort_order;

on conflict (product_id,application_id) do update set sort_order=excluded.sort_order;

on conflict (id) do update set question=excluded.question,answer=excluded.answer,product_id=excluded.product_id,content_generated_by=excluded.content_generated_by,ai_core_version=excluded.ai_core_version,status=excluded.status,sort_order=excluded.sort_order;

on conflict (id) do update set key=excluded.key,title=excluded.title,eyebrow=excluded.eyebrow,content=excluded.content,seo_title=excluded.seo_title,seo_description=excluded.seo_description,status=excluded.status;

commit;

select 'systems' as entity,count(*) from public.systems where status='published'
union all select 'technologies',count(*) from public.technologies where status='published'
union all select 'products',count(*) from public.products where status='published'
union all select 'applications',count(*) from public.applications where status='published';
